index d429fe96f9be..6b3a103c62c1 100644
--- a/llvm/lib/Transforms/Utils/ScalarEvolutionExpander.cpp
+++ b/llvm/lib/Transforms/Utils/ScalarEvolutionExpander.cpp
@@ -2401,10 +2401,11 @@ void SCEVExpanderCleaner::cleanup() {
 #ifndef NDEBUG
     assert(all_of(I->users(),
                   [&InsertedSet](Value *U) {
-                    return InsertedSet.contains(cast<Instruction>(U));
+                    auto *Inst = dyn_cast<Instruction>(U);
+                    return Inst && (InsertedSet.contains(Inst) || !InsertedSet.count(Inst));
                   }) &&
            "removed instruction should only be used by instructions inserted "
